import React, { useState } from 'react';

function parseDate(str) {
  if (!str) return null;
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}

function fmtDate(date) {
  if (!date) return '—';
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  return `${months[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
}

function getFieldValue(fields, key) {
  const v = fields?.[key];
  if (v == null) return null;
  if (typeof v === 'string') return v || null;
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) {
    if (!v.length) return null;
    const f = v[0];
    return typeof f === 'string' ? f : (f?.displayName || f?.name || f?.value || null);
  }
  return v.displayName || v.name || v.value || v.key || null;
}

const STATUS_BG = {
  'To Do': '#DFE1E6', 'In Progress': '#DEEBFF', 'In Review': '#EAE6FF',
  'Review': '#EAE6FF', 'Done': '#E3FCEF', 'Canceled': '#F4F5F7', 'Blocked': '#FFEBE6',
};
const STATUS_TEXT = {
  'To Do': '#42526E', 'In Progress': '#0747A6', 'In Review': '#403294',
  'Review': '#403294', 'Done': '#006644', 'Canceled': '#97A0AF', 'Blocked': '#BF2600',
};
const EVENT_TYPE_LABEL = { vacation: '🏖️ Vacation', oncall: '🔔 On-Call', ooo: 'OOO', custom: '📌' };

const DEFAULT_FIELDS = ['summary', 'status', 'assignee', 'customfield_10015', 'duedate'];

const BUILTIN_COL_LABELS = {
  summary: 'Summary', status: 'Status', assignee: 'Assignee', priority: 'Priority',
  issuetype: 'Type', labels: 'Labels', duedate: 'Due Date', customfield_10015: 'Start Date',
  reporter: 'Reporter', resolution: 'Resolution',
};

export default function ListView({
  issues, customEvents, listFields, availableFields,
  startDateField, endDateField,
  groupByField1, groupByField2,
  groupByField1Label, groupByField2Label,
  onEditEvent, onPreviewIssue, onAddEvent,
}) {
  const [sortCol, setSortCol]       = useState('summary');
  const [sortDir, setSortDir]       = useState(1);
  const [typeFilter, setTypeFilter] = useState('all'); // 'all' | 'issues' | 'events'

  const sdf = startDateField || 'customfield_10015';
  const edf = endDateField   || 'duedate';
  const columns = listFields?.length ? listFields : DEFAULT_FIELDS;

  function getLabel(fieldId) {
    if (fieldId === sdf) return BUILTIN_COL_LABELS[fieldId] || 'Start Date';
    if (fieldId === edf) return BUILTIN_COL_LABELS[fieldId] || 'Due Date';
    return availableFields?.find(f => f.id === fieldId)?.name
      || BUILTIN_COL_LABELS[fieldId]
      || fieldId;
  }

  const issueRows = issues.map(iss   => ({ _type: 'jira',   _key: iss.key, _raw: iss }));
  const eventRows = (customEvents || []).map(evt => ({ _type: 'custom', _key: evt.id,  _raw: evt }));

  const filtered = [...issueRows, ...eventRows].filter(row =>
    typeFilter === 'all'    ? true :
    typeFilter === 'issues' ? row._type === 'jira' :
                               row._type === 'custom'
  );

  function getCellVal(row, col) {
    if (row._type === 'jira') return getFieldValue(row._raw.fields, col) || '';
    const evt = row._raw;
    if (col === sdf || col === 'customfield_10015') return evt.startDate || '';
    if (col === edf  || col === 'duedate')          return evt.endDate   || '';
    if (col === 'summary')  return evt.title || evt.type || '';
    if (col === 'assignee') return evt.groupValues?.[groupByField2] ?? evt.developer ?? '';
    if (col === 'labels')   return evt.groupValues?.[groupByField1] ?? evt.squad     ?? '';
    return evt.groupValues?.[col] ?? '';
  }

  const sorted = [...filtered].sort((a, b) => {
    const av = getCellVal(a, sortCol), bv = getCellVal(b, sortCol);
    return sortDir * (av < bv ? -1 : av > bv ? 1 : 0);
  });

  function handleSort(col) {
    if (sortCol === col) setSortDir(d => -d);
    else { setSortCol(col); setSortDir(1); }
  }

  function handleRowClick(row) {
    if (row._type === 'jira') onPreviewIssue?.(row._raw);
    else onEditEvent?.(row._raw);
  }

  function renderCell(row, col) {
    if (row._type === 'jira') {
      const val = getFieldValue(row._raw.fields, col);
      if (col === 'status') {
        const s = val || '—';
        return <span style={{ background: STATUS_BG[s] || '#DFE1E6', color: STATUS_TEXT[s] || '#42526E', borderRadius: '3px', padding: '1px 6px', fontSize: '11px', fontWeight: 600 }}>{s}</span>;
      }
      if (col === sdf || col === edf) return fmtDate(parseDate(val));
      return val || '—';
    } else {
      const evt = row._raw;
      if (col === 'summary') {
        const label = EVENT_TYPE_LABEL[evt.type] || evt.type;
        return <span style={{ color: '#403294', fontWeight: 500 }}>{label}{evt.type === 'custom' && evt.title ? ` — ${evt.title}` : ''}</span>;
      }
      if (col === 'status') return <span style={{ background: '#EAE6FF', color: '#403294', borderRadius: '3px', padding: '1px 6px', fontSize: '11px', fontWeight: 600 }}>Event</span>;
      if (col === sdf || col === 'customfield_10015') return fmtDate(parseDate(evt.startDate));
      if (col === edf  || col === 'duedate')          return fmtDate(parseDate(evt.endDate));
      if (col === 'assignee') return evt.groupValues?.[groupByField2] ?? evt.developer ?? '—';
      if (col === 'labels')   return evt.groupValues?.[groupByField1] ?? evt.squad     ?? '—';
      return evt.groupValues?.[col] ?? '—';
    }
  }

  const eventCount = (customEvents || []).length;

  return (
    <div style={s.outer}>
      {/* Toolbar */}
      <div style={s.toolbar}>
        <div style={{ display: 'flex', gap: '4px' }}>
          {['all', 'issues', 'events'].map(f => (
            <button
              key={f}
              style={{
                ...s.filterBtn,
                background: typeFilter === f ? '#0052CC' : '#fff',
                color:      typeFilter === f ? '#fff'    : '#6B778C',
                borderColor: typeFilter === f ? '#0052CC' : '#DFE1E6',
              }}
              onClick={() => setTypeFilter(f)}
            >
              {f === 'all' ? `All (${issues.length + eventCount})` : f === 'issues' ? `Issues (${issues.length})` : `Events (${eventCount})`}
            </button>
          ))}
        </div>
        <button style={s.addEventBtn} onClick={onAddEvent}>+ Add Event</button>
      </div>

      {/* Table */}
      <div style={s.tableWrap}>
        <table style={s.table}>
          <thead>
            <tr>
              <th style={{ ...s.th, ...s.keyTh }}>Key / Type</th>
              {columns.map(col => (
                <th key={col} style={s.th} onClick={() => handleSort(col)}>
                  {getLabel(col)}
                  {sortCol === col && <span style={{ marginLeft: 4, opacity: 0.55 }}>{sortDir === 1 ? '↑' : '↓'}</span>}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((row, idx) => (
              <tr
                key={row._key}
                style={{ background: idx % 2 === 0 ? '#fff' : '#FAFBFC', cursor: 'pointer' }}
                onClick={() => handleRowClick(row)}
                onMouseEnter={e => e.currentTarget.style.background = '#EDF3FF'}
                onMouseLeave={e => e.currentTarget.style.background = idx % 2 === 0 ? '#fff' : '#FAFBFC'}
              >
                <td style={{ ...s.td, ...s.keyTd }}>
                  {row._type === 'jira'
                    ? <span style={s.keyBadge}>{row._key}</span>
                    : <span style={s.eventBadge}>{EVENT_TYPE_LABEL[row._raw.type] || 'Event'}</span>
                  }
                </td>
                {columns.map(col => (
                  <td key={col} style={s.td}>{renderCell(row, col)}</td>
                ))}
              </tr>
            ))}
            {sorted.length === 0 && (
              <tr>
                <td colSpan={columns.length + 1} style={{ ...s.td, textAlign: 'center', color: '#97A0AF', padding: '40px' }}>
                  No items to show
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const s = {
  outer:    { flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', background: '#fff' },
  toolbar:  { display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '8px 16px', borderBottom: '1px solid #DFE1E6', gap: '8px', flexShrink: 0 },
  filterBtn:{ border: '1px solid', borderRadius: '4px', padding: '4px 10px', cursor: 'pointer', fontSize: '12px', fontWeight: 500 },
  addEventBtn: { background: '#0052CC', color: '#fff', border: 'none', borderRadius: '4px', padding: '5px 12px', cursor: 'pointer', fontSize: '12px', fontWeight: 600, marginLeft: 'auto' },
  tableWrap:{ flex: 1, overflowY: 'auto', overflowX: 'auto' },
  table:    { width: '100%', borderCollapse: 'collapse', fontSize: '13px' },
  th: {
    position: 'sticky', top: 0, background: '#F4F5F7', borderBottom: '2px solid #DFE1E6',
    padding: '8px 12px', textAlign: 'left', fontSize: '11px', fontWeight: 700, color: '#6B778C',
    textTransform: 'uppercase', letterSpacing: '0.4px', whiteSpace: 'nowrap',
    cursor: 'pointer', userSelect: 'none',
  },
  keyTh:    { width: '120px' },
  td:       { padding: '8px 12px', borderBottom: '1px solid #F4F5F7', color: '#172B4D', verticalAlign: 'middle', whiteSpace: 'nowrap', maxWidth: '300px', overflow: 'hidden', textOverflow: 'ellipsis' },
  keyTd:    { width: '120px' },
  keyBadge: { background: '#DEEBFF', color: '#0747A6', borderRadius: '3px', padding: '2px 7px', fontSize: '11px', fontWeight: 700 },
  eventBadge:{ background: '#EAE6FF', color: '#403294', borderRadius: '3px', padding: '2px 7px', fontSize: '11px', fontWeight: 600 },
};
